    /// <summary>
    /// Minimal <see cref="IFileService"/> double that counts how many times
    /// each method is invoked, used to assert the endpoint bodies run exactly
    /// once after the Execute/ExecuteAsync extraction (guards against a helper
    /// that accidentally retries or double-invokes its delegate).
    /// </summary>
    private sealed class CountingFileService : IFileService
    {
        public int BrowseCalls;
        public int SearchCalls;
        public int ResolveCalls;
        public int UploadCalls;
        public int DeleteCalls;
        public int MoveCalls;
        public int CopyCalls;
        public int CreateDirectoryCalls;

        public BrowseResultDto Browse(string relativePath)
        {
            BrowseCalls++;
            return new BrowseResultDto(string.Empty, null, Array.Empty<FileEntryDto>(), 0, 0, 0L);
        }

        public SearchResultDto Search(string query, string relativePath)
        {
            SearchCalls++;
            return new SearchResultDto(string.Empty, string.Empty, Array.Empty<FileEntryDto>());
        }

        public string ResolveFullPath(string relativePath)
        {
            ResolveCalls++;
            return Path.Combine(Path.GetTempPath(), "resolved.txt");
        }

        public Task<string> UploadAsync(string relativeDirPath, IFormFile file)
        {
            UploadCalls++;
            return Task.FromResult(string.Empty);
        }

        public void Delete(string relativePath) => DeleteCalls++;
        public void Move(MoveRequest request) => MoveCalls++;
        public void Copy(CopyRequest request) => CopyCalls++;
        public void CreateDirectory(string relativePath) => CreateDirectoryCalls++;
    }

    // =====================================================================
    // Non-BCL exception subclasses used to prove the translation branches match
    // by inheritance (is-a) rather than by exact runtime type. CustomIOException
    // / CustomArgumentException MUST be caught (they derive from a translated
    // root); CustomException MUST propagate (it derives from plain Exception).
    // =====================================================================

    private sealed class CustomIOException : IOException
    {

content.text:
        public CustomIOException(string message) : base(message) { }
    }

    private sealed class CustomArgumentException : ArgumentException
    {
        public CustomArgumentException(string message) : base(message) { }
    }

    private sealed class CustomException : Exception
    {
        public CustomException(string message) : base(message) { }
    }
}

using Microsoft.AspNetCore.Http;
using TestProject.Models;

namespace TestProject.Services;

/// <summary>
/// Provides path-safe file system operations confined to a configurable
/// home directory. All relative paths are validated so they cannot escape
/// the sandboxed root before any disk access occurs.
/// </summary>
public interface IFileService
{
    /// <summary>
    /// Lists the immediate children of the directory at <paramref name="relativePath"/>,
    /// returning directories first (then files), each sorted by name.
    /// </summary>
    BrowseResultDto Browse(string relativePath);

    /// <summary>
    /// Recursively searches under <paramref name="relativePath"/> for entries
    /// whose name contains <paramref name="query"/> (case-insensitive).
    /// </summary>
    SearchResultDto Search(string query, string relativePath);

    /// <summary>
    /// Resolves a relative path to its absolute, normalized counterpart within
    /// the home root. Used by controllers to stream downloads.
    /// </summary>
    string ResolveFullPath(string relativePath);

    /// <summary>
    /// Writes the uploaded <paramref name="file"/> into the directory at
    /// <paramref name="relativeDirPath"/>, creating it if necessary, and
    /// returns the stored file's normalized relative path (the home root
    /// becomes the empty string). The returned path reflects the sanitized
    /// file name actually written to disk.
    /// </summary>
    Task<string> UploadAsync(string relativeDirPath, IFormFile file);

    /// <summary>
    /// Deletes the file or directory (recursively) at <paramref name="relativePath"/>.
    /// </summary>
    void Delete(string relativePath);

    /// <summary>
    /// Moves the file or directory at <paramref name="request.SourcePath"/> to
    /// <paramref name="request.DestinationPath"/>.
    /// </summary>
    void Move(MoveRequest request);

    /// <summary>
    /// Copies the file or directory at <paramref name="request.SourcePath"/> to
    /// <paramref name="request.DestinationPath"/>.
    /// </summary>
    void Copy(CopyRequest request);

    /// <summary>
    /// Creates the directory at <paramref name="relativePath"/> (including any
    /// missing parent directories), confined to the home root. Idempotent: a
    /// path that already exists as a directory is a no-op.
    /// </summary>
    void CreateDirectory(string relativePath);
}

using System.Reflection;
using Xunit;

namespace TestProject.Tests.TestHelpers;

/// <summary>
/// Reflection-based assertions that pin down the compiled contract of a
/// positional <c>record</c> type. Used by the <c>TestProject.Models</c> DTO
/// characterization tests so that splitting <c>Models/FileSystemModels.cs</c>
/// into per-DTO files is provably behavior-preserving: whichever file a type
/// ends up declared in, its namespace, sealed-record kind, primary-constructor
/// signature (parameter names, types, and order), and the set of public
/// init-only properties must remain byte-for-byte the same.
/// </summary>
internal static class RecordContract
{
    /// <summary>
    /// Asserts <paramref name="type"/> is a sealed, non-abstract, reference-type
    /// record living in <paramref name="expectedNamespace"/>.
    /// </summary>
    public static void AssertSealedRecordInNamespace(Type type, string expectedNamespace)
    {
        Assert.True(type.IsClass,
            $"{type.Name} must be a reference type (class), not a struct.");
        Assert.True(type.IsSealed,
            $"{type.Name} must be sealed (the DTOs are declared `sealed record`).");
        Assert.True(!type.IsAbstract,
            $"{type.Name} must not be abstract.");
        Assert.Equal(expectedNamespace, type.Namespace);
        Assert.True(IsRecord(type),
            $"{type.Name} must be a record (expected the synthesized copy method).");
    }

    /// <summary>
    /// Asserts <paramref name="type"/> declares exactly one public instance
    /// constructor whose parameters match <paramref name="expected"/> in name,
    /// type, and order, AND that each parameter is surfaced as a public
    /// property of the same name and type with no extra public properties.
    /// This pins the positional-record shape (constructor + auto-properties) so
    /// a moved DTO cannot silently gain, lose, reorder, rename, or retype a
    /// field. Note nullable-reference annotations (<c>string?</c> vs
    /// <c>string</c>) are not reflected in <see cref="Type"/> at runtime, so
    /// nullability is pinned separately via construction in the per-type tests.
    /// </summary>
    public static void AssertPositionalContract(
        Type type,
        params (string Name, Type Type)[] expected)
    {
        var constructors = type.GetConstructors();
        Assert.True(constructors.Length == 1,
            $"{type.Name} must declare exactly one public constructor (the " +
            "positional primary constructor); the protected copy constructor " +
            "synthesized for records must not be public. " +
            $"Found {constructors.Length}.");
        var primary = constructors[0];

        var parameters = primary.GetParameters();
        Assert.Equal(expected.Length, parameters.Length);
        for (var i = 0; i < expected.Length; i++)
        {
            Assert.True(
                parameters[i].Name == expected[i].Name &&
                parameters[i].ParameterType == expected[i].Type,
                $"{type.Name} constructor parameter #{i} must be " +
                $"{expected[i].Type.Name} {expected[i].Name}, but was " +
                $"{parameters[i].ParameterType.Name} {parameters[i].Name}.");
        }

        // Public instance properties: exactly the positional ones. The
        // synthesized protected `EqualityContract` property is excluded because
        // GetProperties() returns only public members.
        var properties = type.GetProperties();
        Assert.Equal(expected.Length, properties.Length);
        foreach (var (name, propertyType) in expected)
        {
            var property = type.GetProperty(name);
            Assert.NotNull(property);
            Assert.True(property!.CanRead, $"{type.Name}.{name} must have a getter.");
            Assert.True(property.CanWrite,
                $"{type.Name}.{name} must have an init/set accessor so `with` works.");
            Assert.Equal(propertyType, property.PropertyType);
        }
    }

    /// <summary>
    /// Asserts record value-equality semantics for two instances of the same
    /// type: the virtual <see cref="object.Equals(object)"/> in both
    /// directions, the generic <see cref="EqualityComparer{T}"/> comparer
    /// (which a record backs with its <c>IEquatable&lt;T&gt;</c>
    /// implementation), and — when equal — equal hash codes. Hash-code
    /// inequality is never asserted for non-equal instances (collisions are
    /// legal), but the hash must never differ for equal instances.
    /// </summary>
    public static void AssertEquality<T>(T a, T b, bool expectedEqual)
    {
        Assert.NotNull(a);
        Assert.NotNull(b);
        Assert.Equal(expectedEqual, a!.Equals(b));
        Assert.Equal(expectedEqual, b!.Equals(a));
        Assert.Equal(expectedEqual, EqualityComparer<T>.Default.Equals(a, b));
        if (expectedEqual)
        {
            Assert.Equal(a.GetHashCode(), b.GetHashCode());
        }
    }

    /// <summary>
    /// True when <paramref name="type"/> has the compiler-synthesized record
    /// copy method (<c>&lt;Clone&gt;$</c>), which only records and record
    /// structs emit. Searched across public and non-public instance members.
    /// </summary>
    private static bool IsRecord(Type type) =>
        type.GetMethod(
            "<Clone>$",
            BindingFlags.Instance | BindingFlags.Public | BindingFlags.NonPublic)
        is not null;
}

