// =====================================================================
// Stack-trace preservation for propagated (non-translated) exceptions.
//
// This is the regression contract for the `throw ex` anti-pattern fix.
// The pre-fix helper caught *every* exception and re-threw the
// non-translated ones via `_ => throw ex`, which RESETS the exception's
// stack trace to the rethrow point inside the controller (erasing the
// original throw origin — e.g. the FakeFileService frame). After the fix
// the three translated roots are caught via a `when` filter so every other
// exception is NEVER caught and propagates with its original stack trace
// intact.
//
// These tests assert that the propagated exception's StackTrace still
// contains the ORIGINAL throw frame (the FakeFileService method), which
// only holds when the controller does not re-throw via `throw ex`. They are
// intentionally RED against the buggy `throw ex` implementation and turn
// GREEN once the fix lands (the same red->green flow a reviewer expects for
// a behavior-changing bug fix). The pre-existing propagation tests above
// (Assert.Same, status code) pin everything that must NOT change.
// =====================================================================

[Theory]
[MemberData(nameof(NonTranslatedExceptions))]
public void PropagatedException_PreservesOriginalStackTrace_SyncEndpoint(Exception ex)
{
    // Thrown from FakeFileService.Delete; the controller (Delete -> Execute)
    // must let it propagate without re-throwing. The originating
    // FakeFileService frame must therefore remain in the propagated trace —
    // a `throw ex` would have replaced it with a controller frame.
    var fake = new FakeFileService { DeleteException = ex };
    var controller = CreateController(fake);

    var thrown = Record.Exception(() => controller.Delete("any"));

    AssertOriginalStackTracePreserved(ex, thrown, "FakeFileService");
}

[Theory]
[MemberData(nameof(NonTranslatedExceptions))]
public async Task PropagatedException_PreservesOriginalStackTrace_AsyncEndpoint(Exception ex)
{
    // Same contract on the async path (Upload -> ExecuteAsync). The body is
    // awaited (not unwrapped via .Result/.Wait()), so the synchronous throw
    // inside FakeFileService.UploadAsync surfaces with its original trace.
    var fake = new FakeFileService { UploadException = ex };
    var controller = CreateController(fake);
    var file = FormFileFactory.CreateFormFile("upload.txt", "payload");

    var thrown = await Record.ExceptionAsync(() => controller.Upload("docs", file));

    AssertOriginalStackTracePreserved(ex, thrown, "FakeFileService");
}

[Fact]
public void PropagatedException_OriginalFrameIsTopMost_NotARethrownCopy_SyncEndpoint()
{
    // Stronger than a substring check: the FIRST (top-most) frame of the
    // propagated trace must be the originating FakeFileService method, not a
    // controller rethrow point. With `throw ex` the top-most frame would be
    // a controller method (TranslateException/Execute), so this fails on the
    // buggy code and proves the trace was not reset.
    var ex = new InvalidOperationException("boom");
    var fake = new FakeFileService { DeleteException = ex };
    var controller = CreateController(fake);

    var thrown = Record.Exception(() => controller.Delete("any"));

    Assert.Same(ex, thrown);
    Assert.NotNull(thrown!.StackTrace);
    var topFrame = thrown.StackTrace!
        .Split(new[] { '\r', '\n' }, StringSplitOptions.RemoveEmptyEntries)
        .Select(s => s.Trim())
        .FirstOrDefault();
    Assert.NotNull(topFrame);
    Assert.Contains("FakeFileService", topFrame);
}

[Fact]
public async Task PropagatedException_OriginalFrameIsTopMost_NotARethrownCopy_AsyncEndpoint()
{
    // Same top-most-frame guarantee on the async path.
    var ex = new InvalidOperationException("boom");
    var fake = new FakeFileService { UploadException = ex };
    var controller = CreateController(fake);
    var file = FormFileFactory.CreateFormFile("upload.txt", "payload");

    var thrown = await Record.ExceptionAsync(() => controller.Upload("docs", file));

    Assert.Same(ex, thrown);
    Assert.NotNull(thrown!.StackTrace);
    var topFrame = thrown.StackTrace!
        .Split(new[] { '\r', '\n' }, StringSplitOptions.RemoveEmptyEntries)
        .Select(s => s.Trim())
        .FirstOrDefault();
    Assert.NotNull(topFrame);
    Assert.Contains("FakeFileService", topFrame);
}

/// <summary>
/// Shared assertion: <paramref name="thrown"/> must be the exact same
/// instance as <paramref name="expected"/> AND its propagated stack trace
/// must still reference <paramref name="originMarker"/> — the original
/// throw location. This only holds when the controller never re-throws the
/// exception (i.e. it is not caught at all, via a `when` filter); a
/// `throw ex` would have reset the trace and erased the origin frame.
/// </summary>
private static void AssertOriginalStackTracePreserved(
    Exception expected, Exception? thrown, string originMarker)
{
    Assert.Same(expected, thrown);
    Assert.NotNull(thrown!.StackTrace);
    Assert.Contains(originMarker, thrown.StackTrace);
}

